import psycopg2
from psycopg2 import sql
import getpass
import re

def validate_extension_name(extension_name):
    if not re.match("^[a-zA-Z0-9_]+$", extension_name):
        raise ValueError("Invalid extension name")

def main():
    conn = None
    try:
        host = input("Enter database host: ")
        port = int(input("Enter database port: "))
        db_name = input("Enter database name: ")
        user = input("Enter database username: ")
        password = getpass.getpass("Enter database password: ")

        conn = psycopg2.connect(
            dbname=db_name,
            user=user,
            password=password,
            host=host,
            port=port
        )

        cur = conn.cursor()

        extension_name = input("Enter extension name to install (e.g. plpythonu): ")
        validate_extension_name(extension_name)

        query = sql.SQL("CREATE EXTENSION IF NOT EXISTS {}").format(sql.Identifier(extension_name))
        cur.execute(query)
        conn.commit()
        print(f"Extension {extension_name} installed successfully")

    except psycopg2.Error as e:
        print(f"Error: {e}")
    finally:
        if conn is not None:
            conn.close()

if __name__ == "__main__":
    main()